/**
 * ConvergioEdu Conversation Flow Component
 *
 * The central conversation-first interface that:
 * 1. Shows character selection with photos and introductions
 * 2. Routes student messages to appropriate characters
 * 3. Supports seamless handoffs between characters
 * 4. Offers both text and voice modes for Coach and Buddy
 *
 * Part of I-01: Conversation-First Main Flow
 * Related: #24 MirrorBuddy Issue, #33 Conversation UX, ManifestoEdu.md
 */

'use client';

import { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion';
import {
  Send,
  Mic,
  MicOff,
  Loader2,
  Volume2,
  VolumeX,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import { useSettingsStore } from '@/lib/stores/app-store';
import { logger } from '@/lib/logger';
import { useConversationFlowStore } from '@/lib/stores/conversation-flow-store';
// Note: routeMessage from store is used instead of direct routeToCharacter
import { analyzeHandoff } from '@/lib/ai/handoff-manager';
import { useMethodProgressStore } from '@/lib/stores/method-progress-store';
import type { ExtendedStudentProfile, Subject } from '@/types';
// Tool integration - T-15
import { ToolButtons } from './tool-buttons';
import { ToolPanel } from '@/components/tools/tool-panel';
import type { ToolType, ToolState } from '@/types/tools';

// Map OpenAI function names to ToolType
const FUNCTION_NAME_TO_TOOL_TYPE: Record<string, ToolType> = {
  create_mindmap: 'mindmap',
  create_quiz: 'quiz',
  create_demo: 'demo',
  web_search: 'search',
  create_flashcards: 'flashcard',
  create_diagram: 'diagram',
  create_timeline: 'timeline',
  create_summary: 'summary',
  open_student_summary: 'summary',
};
// Sub-components
import {
  CharacterAvatar,
  MessageBubble,
  HandoffBanner,
  ConversationHeader,
  VoiceCallOverlay,
  CHARACTER_AVATARS,
} from './components';

// Re-export CharacterCard for external use
export { CharacterCard } from './components';

// ============================================================================
// MAIN COMPONENT
// ============================================================================

export function ConversationFlow() {
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [activeTool, setActiveTool] = useState<ToolState | null>(null);
  const [isToolMinimized, setIsToolMinimized] = useState(false);
  const [voiceSessionId, setVoiceSessionId] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const sessionStartTimeRef = useRef<number>(Date.now());
  const _prefersReducedMotion = useReducedMotion(); // For future accessibility features

  // Stores
  const { studentProfile } = useSettingsStore();
  const {
    isActive,
    mode,
    activeCharacter,
    messages,
    pendingHandoff,
    characterHistory,
    sessionId,
    startConversation,
    endConversation: _endConversation, // Available for future explicit end
    addMessage,
    setMode,
    switchToCoach,
    switchToBuddy,
    goBack,
    acceptHandoff,
    dismissHandoff,
    suggestHandoff,
    routeMessage,
    switchToCharacter: _switchToCharacter, // Used internally via specific switch functions
  } = useConversationFlowStore();

  // Extended profile for routing - memoized to avoid unnecessary re-renders
  const extendedProfile: ExtendedStudentProfile = useMemo(() => ({
    ...studentProfile,
    learningDifferences: studentProfile.learningDifferences || [],
    preferredCoach: studentProfile.preferredCoach,
    preferredBuddy: studentProfile.preferredBuddy,
  }), [studentProfile]);

  // Handle tool request from ToolButtons
  const handleToolRequest = useCallback(async (toolType: ToolType) => {
    if (!activeCharacter || isLoading) return;

    // Create tool prompts based on type
    const toolPrompts: Record<ToolType, string> = {
      mindmap: 'Crea una mappa mentale su questo argomento',
      quiz: 'Crea un quiz per verificare la mia comprensione',
      flashcard: 'Crea delle flashcard per memorizzare',
      demo: 'Crea una demo interattiva per visualizzare',
      search: 'Cerca risorse educative su questo argomento',
      webcam: 'Voglio scattare una foto',
      diagram: 'Crea un diagramma',
      timeline: 'Crea una linea del tempo',
      summary: 'Crea un riassunto',
      formula: 'Mostra la formula',
      chart: 'Crea un grafico',
      pdf: 'Analizza il PDF',
      homework: 'Aiutami con i compiti',
    };

    const toolPrompt = toolPrompts[toolType] || `Crea ${toolType}`;
    setInputValue('');
    setIsLoading(true);

    addMessage({ role: 'user', content: toolPrompt });

    // Create initial tool state
    const newTool: ToolState = {
      id: `tool-${Date.now()}`,
      type: toolType,
      status: 'initializing',
      progress: 0,
      content: null,
      createdAt: new Date(),
    };
    setActiveTool(newTool);

    try {
      const response = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          messages: [
            { role: 'system', content: activeCharacter.systemPrompt },
            ...messages
              .filter((m) => m.role !== 'system')
              .map((m) => ({ role: m.role, content: m.content })),
            { role: 'user', content: toolPrompt },
          ],
          maestroId: activeCharacter.id,
          requestedTool: toolType,
        }),
      });

      if (!response.ok) throw new Error('Failed to get response');
      const data = await response.json();

      const assistantContent = data.content || data.message || '';
      addMessage({ role: 'assistant', content: assistantContent });

      // Update tool state based on response
      if (data.toolCalls?.length > 0) {
        const toolCall = data.toolCalls[0];
        // Map function name (create_quiz) to tool type (quiz)
        const mappedToolType = FUNCTION_NAME_TO_TOOL_TYPE[toolCall.type] || toolType;
        // Extract actual data from result object
        const toolContent = toolCall.result?.data || toolCall.result || toolCall.arguments;
        setActiveTool({
          ...newTool,
          type: mappedToolType,
          status: 'completed',
          progress: 1,
          content: toolContent,
        });
      } else {
        // No tool was created, clear the state
        setActiveTool(null);
      }
    } catch (error) {
      logger.error('Tool request error', { error });
      addMessage({
        role: 'assistant',
        content: 'Mi dispiace, non sono riuscito a creare lo strumento. Riprova?',
      });
      setActiveTool({
        ...newTool,
        status: 'error',
        error: 'Errore nella creazione dello strumento',
      });
    } finally {
      setIsLoading(false);
    }
  }, [activeCharacter, isLoading, messages, addMessage]);

  // Auto-scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Focus input when conversation starts
  useEffect(() => {
    if (isActive && mode === 'text') {
      inputRef.current?.focus();
    }
  }, [isActive, mode]);

  // Start conversation on mount if not active
  useEffect(() => {
    if (!isActive) {
      startConversation(extendedProfile);
    }
  }, [isActive, startConversation, extendedProfile]);

  // SSE listener for real-time tool events (Phase 4: Fullscreen Layout)
  useEffect(() => {
    if (!sessionId) return;

    const eventSource = new EventSource(`/api/tools/sse?sessionId=${sessionId}`);

    eventSource.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);

        switch (data.type) {
          case 'connected':
            logger.debug('SSE connected', { sessionId, clientId: data.clientId });
            break;

          case 'tool:created':
            // Tool creation started - show in panel
            setActiveTool({
              id: data.toolId,
              type: data.toolType,
              status: 'initializing',
              progress: 0,
              content: data.data,

content.content:
   250→              content: data.data,
   251→              createdAt: new Date(),
   252→            });
   253→            break;
   254→
   255→          case 'tool:update':
   256→            // Incremental update during building
   257→            setActiveTool((prev) => {
   258→              if (!prev || prev.id !== data.toolId) return prev;
   259→              return {
   260→                ...prev,
   261→                status: 'building',
   262→                progress: data.progress ?? prev.progress,
   263→                content: data.data ?? prev.content,
   264→              };
   265→            });
   266→            break;
   267→
   268→          case 'tool:complete':
   269→            // Tool finished building
   270→            setActiveTool((prev) => {
   271→              if (!prev || prev.id !== data.toolId) return prev;
   272→              return {
   273→                ...prev,
   274→                status: 'completed',
   275→                progress: 1,
   276→                content: data.data ?? prev.content,
   277→              };
   278→            });
   279→            break;
   280→
   281→          case 'tool:error':
   282→            // Tool build failed
   283→            setActiveTool((prev) => {
   284→              if (!prev || prev.id !== data.toolId) return prev;
   285→              return {
   286→                ...prev,
   287→                status: 'error',
   288→                error: data.error || 'Errore durante la creazione',
   289→              };
   290→            });
   291→            break;
   292→
   293→          case 'heartbeat':
   294→            // Keep-alive, no action needed
   295→            break;
   296→
   297→          default:
   298→            logger.debug('Unknown SSE event type', { type: data.type });
   299→        }
   300→      } catch (error) {
   301→        logger.error('SSE message parse error', { error: String(error) });
   302→      }
   303→    };
   304→
   305→    eventSource.onerror = (error) => {
   306→      logger.error('SSE connection error', { error: String(error) });
   307→      // EventSource will automatically try to reconnect
   308→    };
   309→
   310→    return () => {
   311→      eventSource.close();
   312→      logger.debug('SSE connection closed', { sessionId });
   313→    };
   314→  }, [sessionId]);
   315→
   316→  /**
   317→   * Handle sending a message.
   318→   */
   319→  const handleSend = useCallback(async () => {
   320→    if (!inputValue.trim() || isLoading || !activeCharacter) return;
   321→
   322→    const userMessage = inputValue.trim();
   323→    setInputValue('');
   324→    setIsLoading(true);
   325→
   326→    // Add user message
   327→    addMessage({ role: 'user', content: userMessage });
   328→
   329→    try {
   330→      // Route the message to determine if we need to switch characters
   331→      const routingResult = routeMessage(userMessage, extendedProfile);
   332→
   333→      // Track method progress based on intent (autonomy tracking - Issue #28)
   334→      const methodProgressStore = useMethodProgressStore.getState();
   335→
   336→      // Map main Subject type (English) to method-progress Subject type (Italian)
   337→      const mapToMethodSubject = (subject?: Subject): import('@/lib/method-progress/types').Subject | undefined => {
   338→        if (!subject) return undefined;
   339→        const subjectMap: Record<string, import('@/lib/method-progress/types').Subject> = {
   340→          mathematics: 'matematica',
   341→          physics: 'scienze',
   342→          chemistry: 'scienze',
   343→          biology: 'scienze',
   344→          history: 'storia',
   345→          geography: 'geografia',
   346→          italian: 'italiano',
   347→          english: 'inglese',
   348→          art: 'arte',
   349→          music: 'musica',
   350→        };
   351→        return subjectMap[subject] ?? 'other';
   352→      };
   353→
   354→      if (routingResult.intent.type === 'method_help' ||
   355→          routingResult.intent.type === 'emotional_support') {
   356→        // Student is seeking help - track as help request
   357→        const timeElapsed = Math.round((Date.now() - sessionStartTimeRef.current) / 1000);
   358→        methodProgressStore.recordHelpRequest(
   359→          routingResult.reason,
   360→          timeElapsed,
   361→          mapToMethodSubject(routingResult.intent.subject)
   362→        );
   363→      } else if (routingResult.intent.type === 'academic_help' &&
   364→                 activeCharacter?.type === 'maestro') {
   365→        // Student is working independently with a maestro
   366→        // Only track as "solved alone" if they've been working for a while
   367→        if (messages.length > 4) {
   368→          methodProgressStore.recordProblemSolvedAlone(
   369→            userMessage.slice(0, 100),
   370→            mapToMethodSubject(routingResult.intent.subject)
   371→          );
   372→        }
   373→      }
   374→
   375→      // Check if we should suggest a handoff
   376→      if (
   377→        routingResult.characterType !== activeCharacter.type &&
   378→        routingResult.intent.confidence >= 0.7
   379→      ) {
   380→        // High confidence different character needed - suggest handoff
   381→        const { getMaestroById: _getMaestroById } = await import('@/data/maestri');
   382→        const { getSupportTeacherById } = await import('@/data/support-teachers');
   383→        const { getBuddyById } = await import('@/data/buddy-profiles');
   384→
   385→        let targetCharacter;
   386→        switch (routingResult.characterType) {
   387→          case 'maestro':
   388→            targetCharacter = routingResult.character;
   389→            break;
   390→          case 'coach':
   391→            targetCharacter =
   392→              getSupportTeacherById(extendedProfile.preferredCoach || 'melissa') ||
   393→              routingResult.character;
   394→            break;
   395→          case 'buddy':
   396→            targetCharacter =
   397→              getBuddyById(extendedProfile.preferredBuddy || 'mario') ||
   398→              routingResult.character;
   399→            break;
   400→        }
   401→
   402→        if (targetCharacter && targetCharacter.id !== activeCharacter.id) {
   403→          // Create active character for handoff
   404→          const handoffCharacter = {
   405→            type: routingResult.characterType,
   406→            id: targetCharacter.id,
   407→            name: targetCharacter.name,
   408→            character: targetCharacter,
   409→            greeting:
   410→              routingResult.characterType === 'buddy' && 'getGreeting' in targetCharacter
   411→                ? (targetCharacter as { getGreeting: (p: ExtendedStudentProfile) => string }).getGreeting(extendedProfile)
