   413→            systemPrompt:
   414→              routingResult.characterType === 'buddy' && 'getSystemPrompt' in targetCharacter
   415→                ? (targetCharacter as { getSystemPrompt: (p: ExtendedStudentProfile) => string }).getSystemPrompt(extendedProfile)
   416→                : 'systemPrompt' in targetCharacter ? String(targetCharacter.systemPrompt) : '',
   417→            color: targetCharacter.color,
   418→            voice: 'voice' in targetCharacter ? targetCharacter.voice : 'alloy',
   419→            voiceInstructions: 'voiceInstructions' in targetCharacter ? targetCharacter.voiceInstructions : '',
   420→          };
